'use client';

import { useState, useEffect, useCallback, Suspense } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { supabase } from '@/lib/supabaseClient';
import styles from '../admin.module.css';

const BUSINESS_TYPE_LABELS: Record<string, string> = {
    beauty_hair: '?귨툘 酉고떚 쨌 ?ㅼ뼱',
    beauty_nail: '?뭶 酉고떚 쨌 ?ㅼ씪',
    beauty_body: '?썎 酉고떚 쨌 諛붾뵒',
    beauty_makeup: '?뭵 酉고떚 쨌 硫붿씠?ъ뾽',
    food_general: '?띂截?留쏆쭛 쨌 ?쇰컲',
    food_vegan: '?쪞 留쏆쭛 쨌 鍮꾧굔',
    food_halal: '?븣 留쏆쭛 쨌 ?좊엫',
    landmark: '?뿺截??쒕뱶留덊겕',
    other: '?뱥 湲고?',
};


type PartnerStatus = 'pending' | 'approved' | 'rejected';

interface Partner {
    id: number;
    company_name: string;
    business_type: string;
    contact_name: string;
    email: string;
    phone: string;
    address: string | null;
    website: string | null;
    description: string | null;
    status: PartnerStatus;
    reject_reason: string | null;
    created_at: string;
    reviewed_at: string | null;
}

function AdminPartnersContent() {
    const router = useRouter();
    const searchParams = useSearchParams();
    const [partners, setPartners] = useState<Partner[]>([]);
    const [loading, setLoading] = useState(true);
    const [tab, setTab] = useState<PartnerStatus | 'all'>(
        (searchParams.get('tab') as PartnerStatus | 'all') ?? 'pending'
    );
    const [actionLoading, setActionLoading] = useState<number | null>(null);
    const [rejectTarget, setRejectTarget] = useState<Partner | null>(null);
    const [rejectReason, setRejectReason] = useState('');
    const [isAdmin, setIsAdmin] = useState<boolean | null>(null);

    // 愿由ъ옄 ?щ? ?뺤씤
    useEffect(() => {
        const checkAdmin = async () => {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) { setIsAdmin(false); return; }

            const { data: profile } = await supabase
                .from('profiles')
                .select('is_admin')
                .eq('id', user.id)
                .maybeSingle();

            setIsAdmin(profile?.is_admin === true);
        };
        checkAdmin();
    }, []);

    const fetchPartners = useCallback(async () => {
        setLoading(true);
        let query = supabase
            .from('partners')
            .select('*')
            .order('created_at', { ascending: false });

        if (tab !== 'all') {
            query = query.eq('status', tab);
        }

        const { data, error } = await query;
        if (!error) setPartners((data as Partner[]) || []);
        setLoading(false);
    }, [tab]);

    useEffect(() => {
        if (isAdmin) fetchPartners();
    }, [isAdmin, fetchPartners]);

    const handleApprove = async (partner: Partner) => {
        setActionLoading(partner.id);
        await supabase
            .from('partners')
            .update({ status: 'approved', reviewed_at: new Date().toISOString() })
            .eq('id', partner.id);
        await fetchPartners();
        setActionLoading(null);
    };

    const handleRejectSubmit = async () => {
        if (!rejectTarget) return;
        setActionLoading(rejectTarget.id);
        await supabase
            .from('partners')
            .update({
                status: 'rejected',
                reject_reason: rejectReason || '愿由ъ옄???섑빐 嫄곗젅?섏뿀?듬땲??',
                reviewed_at: new Date().toISOString(),
            })
            .eq('id', rejectTarget.id);
        setRejectTarget(null);
        setRejectReason('');
        await fetchPartners();
        setActionLoading(null);
    };

    const counts = {
        all: partners.length,
        pending: partners.filter(p => p.status === 'pending').length,
        approved: partners.filter(p => p.status === 'approved').length,
        rejected: partners.filter(p => p.status === 'rejected').length,
    };

    const formatDate = (iso: string) => {
        try {
            return new Date(iso).toLocaleDateString('ko-KR', { year: 'numeric', month: 'short', day: 'numeric' });
        } catch { return iso; }
    };

    // 鍮꾧?由ъ옄 ?묎렐 李⑤떒
    if (isAdmin === false) {
        return (
            <div style={{
                minHeight: '100vh', display: 'flex', flexDirection: 'column',
                alignItems: 'center', justifyContent: 'center',
                gap: 16, background: 'var(--background)', padding: 24,
            }}>
                <div style={{ fontSize: '3rem' }}>?뵏</div>
                <h2 style={{ fontWeight: 700, fontSize: '1.2rem', margin: 0 }}>愿由ъ옄 ?꾩슜 ?섏씠吏</h2>
                <p style={{ color: 'var(--gray-500)', fontSize: '0.9rem', textAlign: 'center' }}>
                    ???섏씠吏??愿由ъ옄留??묎렐?????덉뒿?덈떎.<br />
                    Supabase?먯꽌 is_admin 沅뚰븳??遺?щ컺?쇱꽭??
                </p>
                <button
                    onClick={() => router.push('/')}
                    style={{
                        padding: '12px 28px', background: 'var(--primary)', color: 'white',
                        border: 'none', borderRadius: 14, fontWeight: 700, cursor: 'pointer'
                    }}
                >?덉쑝濡??대룞</button>
            </div>
        );
    }

    if (isAdmin === null) {
        return (
            <div style={{
                minHeight: '100vh', display: 'flex', alignItems: 'center',
                justifyContent: 'center', background: 'var(--background)',
            }}>
                <div style={{
                    width: 36, height: 36, border: '3px solid var(--primary)',
                    borderTopColor: 'transparent', borderRadius: '50%',
                    animation: 'spin 0.8s linear infinite',
                }} />
                <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
            </div>
        );
    }

    const displayed = tab === 'all' ? partners : partners.filter(p => p.status === tab);

    const TAB_CONFIG: { key: PartnerStatus | 'all'; label: string }[] = [
        { key: 'pending', label: `???湲?${counts.pending}` },
        { key: 'approved', label: `???뱀씤 ${counts.approved}` },
        { key: 'rejected', label: `??嫄곗젅 ${counts.rejected}` },
        { key: 'all', label: `?뱥 ?꾩껜` },
    ];

    return (
        <div className={styles.container}>
            {/* Header */}
            <header className={styles.header}>
                <button
                    onClick={() => router.push('/admin')}
                    style={{ background: 'none', border: 'none', fontSize: '1.4rem', cursor: 'pointer', color: 'var(--foreground)' }}
                >??/button>
                <h1 className={styles.headerTitle}>?쩃 ?묐젰?낆껜 愿由?/h1>
                <span className={styles.adminBadge}>ADMIN</span>
            </header>

            {/* Tab Bar */}
            <div className={styles.tabBar}>
                {TAB_CONFIG.map(t => (
                    <button
                        key={t.key}
                        className={`${styles.tab} ${tab === t.key ? styles.tabActive : ''}`}
                        onClick={() => setTab(t.key)}
                    >
                        {t.label}
                    </button>
                ))}
            </div>

            {/* Content */}
            <div className={styles.content}>
                {loading && (
                    <div style={{ textAlign: 'center', padding: '60px 0', color: 'var(--gray-400)' }}>遺덈윭?ㅻ뒗 以?..</div>
                )}

                {!loading && displayed.length === 0 && (
                    <div className={styles.empty}>
                        <div className={styles.emptyIcon}>
                            {tab === 'pending' ? '?? : tab === 'approved' ? '?? : '?뱥'}
                        </div>
                        <p style={{ color: 'var(--gray-500)', fontSize: '0.95rem' }}>
                            {tab === 'pending' ? '?湲?以묒씤 ?좎껌???놁뒿?덈떎.' : `?대떦 紐⑸줉??鍮꾩뼱?덉뒿?덈떎.`}
                        </p>
                    </div>
                )}

                {!loading && displayed.map(partner => (
                    <div key={partner.id} className={styles.card}>
                        <div className={styles.cardHeader}>
                            <div className={styles.avatar}>
                                {BUSINESS_TYPE_LABELS[partner.business_type]?.split(' ')[0] ?? '?룫'}
                            </div>
                            <div className={styles.cardInfo}>
                                <div className={styles.companyName}>{partner.company_name}</div>
                                <div className={styles.meta}>
                                    {BUSINESS_TYPE_LABELS[partner.business_type] ?? partner.business_type} 쨌 {formatDate(partner.created_at)}
                                </div>
                            </div>
                            <span className={`${styles.statusBadge} ${partner.status === 'pending' ? styles.statusPending :
                                partner.status === 'approved' ? styles.statusApproved :
                                    styles.statusRejected
                                }`}>
                                {partner.status === 'pending' ? '?湲? : partner.status === 'approved' ? '?뱀씤' : '嫄곗젅'}
                            </span>
                        </div>

                        {/* ?곸꽭 ?뺣낫 */}
                        <div className={styles.details}>
                            <div className={styles.detailRow}>
                                <span className={styles.detailLabel}>?대떦??/span>
                                <span className={styles.detailValue}>{partner.contact_name}</span>
                            </div>
                            <div className={styles.detailRow}>
                                <span className={styles.detailLabel}>?곕씫泥?/span>
                                <span className={styles.detailValue}>{partner.phone}</span>
                            </div>
                            <div className={styles.detailRow}>
                                <span className={styles.detailLabel}>?대찓??/span>
                                <span className={styles.detailValue}>{partner.email}</span>
                            </div>
                            {partner.address && (
                                <div className={styles.detailRow}>
                                    <span className={styles.detailLabel}>二쇱냼</span>
                                    <span className={styles.detailValue}>{partner.address}</span>
                                </div>
                            )}
                            {partner.website && (
                                <div className={styles.detailRow}>
                                    <span className={styles.detailLabel}>?뱀궗?댄듃</span>
                                    <a href={partner.website} target="_blank" rel="noreferrer"
                                        className={styles.detailValue}
                                        style={{ color: 'var(--primary)', textDecoration: 'underline' }}
                                    >
                                        {partner.website}
                                    </a>
                                </div>
                            )}
                        </div>

                        {partner.description && (
                            <div className={styles.desc}>{partner.description}</div>
                        )}

                        {partner.status === 'rejected' && partner.reject_reason && (
                            <div style={{
                                background: '#fef2f2', border: '1px solid #fecaca',
                                borderRadius: 10, padding: '10px 12px',
                                fontSize: '0.82rem', color: '#dc2626',
                                marginBottom: 10, lineHeight: 1.5,
                            }}>
                                <strong>嫄곗젅 ?ъ쑀:</strong> {partner.reject_reason}
                            </div>
                        )}

                        {/* ?≪뀡 踰꾪듉 (?湲?以묒씪 ?뚮쭔) */}
                        {partner.status === 'pending' && (
                            <div className={styles.actionRow}>
                                <button
                                    className={styles.approveBtn}
                                    disabled={actionLoading === partner.id}
                                    onClick={() => handleApprove(partner)}
                                >
                                    ???뱀씤
                                </button>
                                <button
                                    className={styles.rejectBtn}
                                    disabled={actionLoading === partner.id}
                                    onClick={() => { setRejectTarget(partner); setRejectReason(''); }}
                                >
                                    ??嫄곗젅
                                </button>
                            </div>
                        )}
                    </div>
                ))}
            </div>

            {/* 嫄곗젅 ?ъ쑀 紐⑤떖 */}
            {rejectTarget && (
                <div className={styles.rejectModal} onClick={() => setRejectTarget(null)}>
                    <div className={styles.rejectSheet} onClick={e => e.stopPropagation()}>
                        <h3 className={styles.rejectSheetTitle}>??嫄곗젅 ?ъ쑀 ?낅젰</h3>
                        <p style={{ fontSize: '0.85rem', color: 'var(--gray-500)', marginBottom: 12 }}>
                            <strong>{rejectTarget.company_name}</strong> ?좎껌??嫄곗젅?⑸땲??
                        </p>
                        <textarea
                            className={styles.rejectInput}
                            value={rejectReason}
                            onChange={e => setRejectReason(e.target.value)}
                            placeholder="嫄곗젅 ?ъ쑀瑜??낅젰?섏꽭??(?좏깮?ы빆)"
                        />
                        <button
                            className={styles.rejectConfirmBtn}
                            onClick={handleRejectSubmit}
                            disabled={actionLoading !== null}
                        >
                            嫄곗젅 ?뺤젙
                        </button>
                        <button className={styles.cancelBtn} onClick={() => setRejectTarget(null)}>
                            痍⑥냼
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

export default function AdminPartnersPage() {
    return (
        <Suspense fallback={
            <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'var(--background)' }}>
                <div style={{ width: 36, height: 36, border: '3px solid var(--primary)', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 0.8s linear infinite' }} />
                <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
            </div>
        }>
            <AdminPartnersContent />
        </Suspense>
    );
}

