                                <button className={styles.filterChip} key={opt}>{t(`explore_page.filters.options.${opt}`)}</button>
                            ))}
                        </div>
                        <h4>{t('explore_page.filters.ingredients')}</h4>
                        <div className={styles.filterSection}>
                            {['beef', 'pork', 'chicken', 'seafood', 'dairy', 'egg'].map(opt => (
                                <button className={styles.filterChip} key={opt}>{t(`explore_page.filters.options.${opt}`)}</button>
                            ))}
                        </div>
                    </>
                );
            case 'event':
                return (
                    <>
                        <h4>{t('explore_page.filters.date')}</h4>
                        <div className={styles.filterSection}>
                            {['today', 'weekend', 'select'].map(opt => (
                                <button className={styles.filterChip} key={opt}>{t(`explore_page.filters.options.${opt}`)}</button>
                            ))}
                        </div>
                        <h4>{t('explore_page.filters.type')}</h4>
                        <div className={styles.filterSection}>
                            {['concert', 'show', 'popup', 'club', 'exhibition'].map(opt => (
                                <button className={styles.filterChip} key={opt}>{t(`explore_page.filters.options.${opt}`)}</button>
                            ))}
                        </div>
                    </>
                );
            default:
                return <p>{t('explore_page.no_specific_filters')}</p>;
        }
    }

    if (!isOpen) return null;

    return (
        <div className={styles.modalOverlay} onClick={onClose}>
            <div className={`${styles.bottomSheet} slide-up`} onClick={e => e.stopPropagation()}>
                <div className={styles.sheetHeader}>
                    <button onClick={() => setSelectedFilters({})} className={styles.resetBtn}>{t('explore_page.reset')}</button>
                    <h3>{t('explore_page.filters_title')}</h3>
                    <button onClick={() => { onApply(selectedFilters); onClose(); }} className={styles.applyBtn}>{t('explore_page.apply')}</button>
                </div>
                <div className={styles.sheetContent}>
                    {renderFilters()}
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import styles from '../explore.module.css';
import { useTranslation } from 'react-i18next';

interface HotelSearchProps {
    onSelect: (location: { lat: number, lng: number, name: string, placeId: string }) => void;
}

export default function HotelSearch({ onSelect }: HotelSearchProps) {
    const { t } = useTranslation('common');
    const [input, setInput] = useState('');
    const [suggestions, setSuggestions] = useState<any[]>([]);
    const [isOpen, setIsOpen] = useState(false);
    const wrapperRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    const handleInput = async (val: string) => {
        setInput(val);
        if (val.length < 2) {
            setSuggestions([]);
            return;
        }

        try {
            const res = await fetch('/api/places/autocomplete', {
                method: 'POST',
                body: JSON.stringify({ input: val }),
            });
            const data = await res.json();
            setSuggestions(data.suggestions || []);
            setIsOpen(true);
        } catch (error) {
            console.error('Autocomplete error:', error);
        }
    };

    const handleSelect = async (suggestion: any) => {
        const id = suggestion.placePrediction.placeId;
        const name = suggestion.placePrediction.text.text;
        setInput(name);
        setIsOpen(false);

        try {
            const res = await fetch(`/api/places/details?placeId=${id}`);
            const data = await res.json();
            if (data.location) {
                onSelect({
                    lat: data.location.latitude,
                    lng: data.location.longitude,
                    name: name,
                    placeId: id
                });
            }
        } catch (error) {
            console.error('Details error:', error);
        }
    };

    return (
        <div className={styles.hotelSearchWrapper} ref={wrapperRef}>
            <div className={styles.hotelSearchInputBox}>
                <input
                    type="text"
                    placeholder="Hotel / Address in Korea"
                    value={input}
                    onChange={(e) => handleInput(e.target.value)}
                    onFocus={() => input.length >= 2 && setIsOpen(true)}
                />
            </div>

            {isOpen && suggestions.length > 0 && (
                <ul className={styles.suggestionsList}>
                    {suggestions.map((s, i) => (
                        <li key={i} onClick={() => handleSelect(s)}>
                            <span className={styles.suggestionIcon}>?뱧</span>
                            <span className={styles.suggestionText}>{s.placePrediction.text.text}</span>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

