import { supabase } from "@/lib/supabaseClient";

function MyPageContent() {
    const { t } = useTranslation("common");
    const router = useRouter();
    const searchParams = useSearchParams();
    const { itinerary } = useTrip();
    const hasNewBooking = searchParams.get('booked') === 'true';

    const [userName, setUserName] = useState("Jessie Kim");
    const [myPosts, setMyPosts] = useState<any[]>([]);
    const [isAdmin, setIsAdmin] = useState(false);
    const [partnerStatus, setPartnerStatus] = useState<null | 'pending' | 'approved' | 'rejected' | 'none'>(null);
    const [userEmail, setUserEmail] = useState<string>('');

    useEffect(() => {
        const storedUser = localStorage.getItem('user');
        if (storedUser) {
            try {
                const parsed = JSON.parse(storedUser);
                if (parsed.name) setUserName(parsed.name);
            } catch (e) {
                // Ignore parse errors
            }
        }

        // 愿由ъ옄 ?щ? ?뺤씤 + ?묐젰?낆껜 ?좎껌 ?곹깭 ?뺤씤
        const checkAdmin = async () => {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return;

            const email = user.email ?? '';
            setUserEmail(email);

            const { data: profile } = await supabase
                .from('profiles')
                .select('is_admin')
                .eq('id', user.id)
                .maybeSingle();
            if (profile?.is_admin) setIsAdmin(true);

            // ?묐젰?낆껜 ?좎껌 ?곹깭 ?뺤씤
            const { data: partner } = await supabase
                .from('partners')
                .select('status')
                .eq('email', email)
                .maybeSingle();

            setPartnerStatus(partner ? partner.status : 'none');
        };
        checkAdmin();
    }, []);

    useEffect(() => {
        const fetchMyPosts = async () => {
            if (!userName) return;
            const { data, error } = await supabase
                .from('community_posts')
                .select('*')
                .eq('author', userName)
                .order('created_at', { ascending: false });

            if (data && !error) {
                setMyPosts(data);
            }
